parameters.jsCode:
const items = $input.all();
const results = [];

function repairJSON(text) {
  // Try parsing as-is first
  try { return JSON.parse(text); } catch(e) {}

  // Common fixes
  let fixed = text;
  // Fix missing closing braces in arrays: "value" ,\n{ -> "value" },\n{
  fixed = fixed.replace(/(\d+\.?\d*)\s*\n\s*,\s*\n?\s*\{/g, '$1\n    },\n    {');
  fixed = fixed.replace(/(")\s*\n\s*,\s*\n?\s*\{/g, '$1\n    },\n    {');
  // Fix trailing commas before ] or }
  fixed = fixed.replace(/,\s*([\]}])/g, '$1');

  try { return JSON.parse(fixed); } catch(e) {}

  // More aggressive: balance braces
  let openBrace = 0, openBracket = 0;
  for (const c of fixed) {
    if (c === '{') openBrace++;
    if (c === '}') openBrace--;
    if (c === '[') openBracket++;
    if (c === ']') openBracket--;
  }
  while (openBracket > 0) { fixed += ']'; openBracket--; }
  while (openBrace > 0) { fixed += '}'; openBrace--; }

  try { return JSON.parse(fixed); } catch(e2) {
    throw new Error('JSON repair failed: ' + e2.message);
  }
}

for (const item of items) {
  try {
    let data;
    const resp = item.json;
    if (resp.candidates && resp.candidates[0]) {
      const text = resp.candidates[0].content?.parts?.[0]?.text || '{}';
      data = repairJSON(text);
    } else if (resp.error) {
      throw new Error(typeof resp.error === 'string' ? resp.error : resp.error.message || 'Gemini error');
    } else {
      data = resp;
    }
    const now = new Date().toISOString();
    const poNr = 'PO-' + new Date().getFullYear() + '-' + String(Date.now()).slice(-6);
    const positionen = (data.positionen || []).map(p => ({
      bezeichnung: p.bezeichnung || '', menge: parseFloat(p.menge) || 1,
      einheit: p.einheit || 'Stk.', ekPreis: parseFloat(p.einzelpreis) || 0,
      gelieferteMenge: parseFloat(p.menge) || 1, gesamtpreis: parseFloat(p.gesamtpreis) || 0
    }));
    const po = {
      id: poNr, nummer: poNr, status: 'geliefert',
      lieferant_name: data.lieferant_name || 'Unbekannt',
      lieferant_email: data.lieferant_email || '',
      lieferant_telefon: data.lieferant_telefon || '',
      lieferant_ansprechpartner: data.ansprechpartner || '',
      positionen, netto: parseFloat(data.netto) || 0,
      mwst: parseFloat(data.mwst_betrag) || 0, brutto: parseFloat(data.brutto) || 0,
      bestelldatum: data.rechnungs_datum || now.split('T')[0],
      lieferdatum_erwartet: data.liefer_datum || data.rechnungs_datum || now.split('T')[0],
      lieferdatum_tatsaechlich: data.liefer_datum || data.rechnungs_datum || now.split('T')[0],
      notizen: ['Automatisch erfasst aus E-Mail.',
        data.rechnungs_nr ? 'Eingangsrechnung: ' + data.rechnungs_nr : '',
        data.zahlungsfrist ? 'Zahlungsfrist: ' + data.zahlungsfrist : '',
        data.kunden_nr ? 'Kunden-Nr: ' + data.kunden_nr : '',
        data.iban ? 'IBAN: ' + data.iban : ''
      ].filter(Boolean).join('\n'),
      created_at: now, updated_at: now,
      eingangsrechnung_nr: data.rechnungs_nr || '',
      eingangsrechnung_datum: data.rechnungs_datum || '',
      zahlungsfrist_datum: data.zahlungsfrist || '',
      confidence: parseFloat(data.confidence) || 0.5
    };
    results.push({ json: { po, raw_data: data } });
  } catch (err) {
    results.push({ json: { error: err.message, raw: item.json } });
  }
}
return results;

